  ('aboriginal-f0899a01-moex-00137', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政契約之執行，下列敘述何者正確？', '["關於行政契約之強制執行，準用民事訴訟法有關強制執行之規定", "行政契約約定自願接受執行，締約之一方為地方自治團體之行政機關時，應經該地方自治團體之議會 認可", "行政契約約定自願接受執行，契約內容涉及委辦事項者，應經自治機關之中央主管機關之認可，始生 效力", "行政契約若有約定自願接受強制執行者，債務人不為給付時，債權人得以該契約為強制執行之執行 名義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00138', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政指導之敘述，下列何者錯誤？', '["行政指導原則上採書面要式主義", "行政指導如遭相對人明確拒絕時，行政機關應即停止，並不得據此對相對人為不利之處置", "行政機關之行政指導如有違法，並侵害人民權利時，人民得請求國家賠償", "行政指導並無法律上之拘束力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00139', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '甲鄉公所與乙環保清運公司訂立廢棄物清運契約，委由乙定期清運廢棄物；後經強颱侵襲，造成淹水， 民眾丟棄之廢棄物大增，乙之清運成本難以承受，非締約當時所得預見，遂向甲主張應增加清運費用 之給付。此係基於下列何種原則？', '["期待可能性原則", "信賴保護原則", "情事變更原則", "比例原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00140', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政罰之敘述，下列何者正確？', '["罰金屬於行政罰", "怠金為行政罰法所明定之裁罰性不利處分", "命拆除違章建築屬於行政罰", "公告姓名為裁罰性之不利處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00141', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '社會秩序維護法上所規定之拘留，其法律性質為何？', '["秩序罰", "行政刑罰", "執行罰", "刑罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00142', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依行政罰法規定，行政機關對現行違反行政法上義務之行為人，強制其到指定處所查證身分，如有不 服時，得為下列何種救濟？', '["向執行職務之人員，當場陳述理由表示異議", "向執行職務人員之所屬機關聲明異議", "向執行職務人員之上級機關聲明異議", "因屬行政調查必要之手段，故不得為任何救濟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00143', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於公法上金錢給付義務之行政執行，下列敘述何者正確？', '["公法上金錢給付義務之執行機關為原處分機關及其上級機關", "對於公法上金錢給付義務之執行允許再行查封", "違反道路交通管理處罰條例所受之裁罰處分可以作為行政執行之執行名義", "基於責罰相當原則禁止採用限制人身自由之執行方式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00144', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政機關命停業處分之行政執行，下列敘述何者正確？', '["若主管機關命停業期間為8月1日至8月8日，期間經過後，仍得處以怠金", "行政機關得命他人代履行", "執行得因受執行人聲明異議，而停止執行", "如違規應受停業及罰鍰之處罰，違規行為人拒不停業時，主管機關仍得處以怠金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00145', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '甲積欠稅金與罰鍰超過新臺幣10萬元，由其生活型態、消費方式觀察，甲顯有清償之能力，但甲卻 始終表示自己無法還款，行政執行機關除得命其提供擔保，限期履行外，依法並得採取下列何種措施？', '["向法院聲請裁定管收", "由警察機關陪同拘提甲", "限制甲之住居", "向法院聲請假處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00146', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於訴願決定之敘述，下列何者正確？', '["訴願書不符合法定程式而無法補正者，訴願機關應作成無理由之決定", "對於已決定之訴願事件重行提起訴願者，訴願機關應作成無理由之決定", "訴願機關於審理後認為訴願有理由者，應撤銷原處分，並得命原處分機關另為處分", "基於行政一體原則，訴願機關於訴願人表示不服之範圍內，得為更不利訴願人之處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
